# =============================================================================
# SHAP Dependence Explorer
# =============================================================================
# Usage: Set `feature` below to any model feature name, then source this file
# or run the blocks interactively. Produces both ggplot and plotly charts.
#
# The CSV is auto-generated by train_model.py each time you retrain.
# Available features are printed on load.
# =============================================================================

library(ggplot2)
library(plotly)

# --- Load SHAP data ---
shap_path <- "data/shap_all.csv"
if (!file.exists(shap_path)) {
  stop("data/shap_all.csv not found. Run train_model.py to generate it.")
}
shap_raw <- read.csv(shap_path)

# Extract feature names from column pattern: {feature}_value / {feature}_shap
value_cols <- grep("_value$", names(shap_raw), value = TRUE)
available_features <- sub("_value$", "", value_cols)

# --- Shared theme ---
theme_shap <- theme_minimal(base_size = 12) +
  theme(
    plot.title    = element_text(face = "bold", size = 14),
    plot.subtitle = element_text(size = 10, color = "gray40"),
    panel.grid.minor = element_blank()
  )


# =============================================================================
# SET YOUR FEATURE HERE
# =============================================================================
feature <- "diff_run_win_pct"
# =============================================================================


# --- Validate feature ---
if (!feature %in% available_features) {
  stop(paste0("Feature '", feature, "' not found. See available_features above."))
}

# --- Build plot dataframe ---
plot_df <- data.frame(
  value     = shap_raw[[paste0(feature, "_value")]],
  shap      = shap_raw[[paste0(feature, "_shap")]],
  neutral   = factor(shap_raw$neutral_site, levels = c(0, 1),
                     labels = c("Non-neutral", "Neutral")),
  winner    = factor(shap_raw$home_winner, levels = c(0, 1),
                     labels = c("Away win", "Home win")),
  progress  = shap_raw$season_progress
)
plot_df <- plot_df[complete.cases(plot_df), ]

r_val <- round(cor(plot_df$value, plot_df$shap, use = "complete.obs"), 3)

# =============================================================================
# ggplot — Static dependence plot
# =============================================================================
p_gg <- ggplot(plot_df, aes(x = value, y = shap)) +
  geom_point(aes(color = neutral), alpha = 0.10, size = 0.6) +
  geom_smooth(method = "loess", se = TRUE, color = "red", linewidth = 0.8) +
  geom_hline(yintercept = 0, linetype = "dashed", color = "gray50") +
  geom_vline(xintercept = 0, linetype = "dotted", color = "gray70") +
  scale_color_manual(values = c("Non-neutral" = "steelblue",
                                "Neutral"     = "darkorange")) +
  labs(
    title    = paste0(feature, " — SHAP Dependence"),
    subtitle = paste0("r = ", r_val, "  |  n = ", nrow(plot_df),
                      "  |  positive SHAP = favors home"),
    x        = feature,
    y        = "SHAP contribution (log-odds)",
    color    = "Game type"
  ) +
  theme_shap +
  theme(
    legend.position = c(0.15, 0.85),
    legend.background = element_rect(fill = "white", color = NA)
  )

print(p_gg)

# =============================================================================
# plotly — Interactive dependence plot
# =============================================================================
p_ly <- plot_ly(
  data   = plot_df,
  x      = ~value,
  y      = ~shap,
  color  = ~neutral,
  colors = c("Non-neutral" = "steelblue", "Neutral" = "darkorange"),
  type   = "scatter",
  mode   = "markers",
  marker = list(size = 3, opacity = 0.15),
  text   = ~paste0(
    feature, ": ", round(value, 3),
    "<br>SHAP: ", round(shap, 4),
    "<br>", as.character(neutral),
    "<br>", as.character(winner),
    "<br>Season progress: ", round(progress, 2)
  ),
  hoverinfo = "text"
) %>%
  layout(
    title = list(
      text = paste0(feature, " — SHAP Dependence (r = ", r_val, ")"),
      font = list(size = 16)
    ),
    xaxis = list(title = feature, zeroline = TRUE),
    yaxis = list(title = "SHAP contribution (log-odds)", zeroline = TRUE),
    shapes = list(
      list(type = "line", x0 = 0, x1 = 0,
           y0 = min(plot_df$shap), y1 = max(plot_df$shap),
           line = list(color = "gray70", dash = "dot")),
      list(type = "line",
           x0 = min(plot_df$value), x1 = max(plot_df$value),
           y0 = 0, y1 = 0,
           line = list(color = "gray50", dash = "dash"))
    )
  )

p_ly
